import{_ as e,c as r,o as i,ag as a}from"./chunks/framework.CDhRSyRB.js";const m=JSON.parse('{"title":"Git 常用操作","description":"","frontmatter":{},"headers":[],"relativePath":"articles/Git/Git常用操作.md","filePath":"articles/Git/Git常用操作.md"}'),n={name:"articles/Git/Git常用操作.md"};function o(g,t,l,s,c,h){return i(),r("div",null,t[0]||(t[0]=[a('<h1 id="git-常用操作" tabindex="-1">Git 常用操作 <a class="header-anchor" href="#git-常用操作" aria-label="Permalink to &quot;Git 常用操作&quot;">​</a></h1><p>克隆仓库：git clone <a href="https://github.com/xxx.git" target="_blank" rel="noreferrer">https://github.com/xxx.git</a><br> 创建分支：git branch [name]<br> 切换分支: git checkout [name]<br> 检出分支: git checkout -b [name]<br> 新增远程分支：git push --set-upstream origin xxx<br> 抓取远程分支：git fetch origin [name]<br> 同步远程分支：git pull origin [name]<br> 删除本地分支：git branch -d [name]<br> 删除远程分支：git push origin --delete [name]<br> 查看远程仓库地址：git remote -v<br> 添加远程仓库：git remote add origin <a href="https://github.com/xxx/xxx.git" target="_blank" rel="noreferrer">https://github.com/xxx/xxx.git</a><br> 抓取远程仓库：git fetch [remote-name]<br> 同步远程仓库：git pull [remote-name]<br> 查看标签：git tag<br> 添加用户：git config --global user.name<br> 注销用户：git config --global --unset user.name<br> 初始化本地库：git init<br> 发布新建的本地分支到远程分支： git push -u origin xxx<br> 更新远程分支列表：git remote update origin --prune<br> 放弃已追踪的某个文件：git update-index --assume-unchanged filename<br> 撤销放弃已追踪的某个文件：git update-index --no-assume-unchanged filename<br> 关闭大小写不敏感：git config core.ignorecase false</p><ul><li><a href="https://git-scm.com/book/zh/v2" target="_blank" rel="noreferrer">Git 官方文档</a></li><li><a href="https://git-scm.com/book/zh/v2/%E8%87%AA%E5%AE%9A%E4%B9%89-Git-Git-%E9%92%A9%E5%AD%90" target="_blank" rel="noreferrer">工作流钩子</a></li><li><a href="https://typicode.github.io/husky/" target="_blank" rel="noreferrer">husky</a></li></ul><h2 id="默认配置文件位置" tabindex="-1">默认配置文件位置 <a class="header-anchor" href="#默认配置文件位置" aria-label="Permalink to &quot;默认配置文件位置&quot;">​</a></h2><p>macos 系统中：<code>~/.gitconfig</code></p>',5)]))}const u=e(n,[["render",o]]);export{m as __pageData,u as default};
